import React from 'react';

const ZoomLogin = () => {
  const handleLogin = () => {
    // Afișează o alertă pentru a verifica dacă butonul funcționează corect
    alert("Autentificare cu Zoom a fost apăsat");
    // Redirecționează către backend pentru login
    window.location.href = '/shortcuts/zoom/oauth/login/';
  };

  return (
    <div>
      <h1>Autentificare cu Zoom</h1>
      <button onClick={handleLogin}>Autentificare cu Zoom</button>
    </div>
  );
};

export default ZoomLogin;
